-- ============================================================================
-- Importação do comparativo técnico Mahindra (especificacoes_detalhadas) — 2026-06-24
--
-- Pré-requisito: rodar antes o supabase-especificacoes-detalhadas.sql (cria a coluna).
-- Rodar em: https://supabase.com/dashboard/project/citrhumdkfivdzbmayde/sql/new
--
-- PASSO 1: confira o mapeamento modelo->ficha (slug) antes dos UPDATEs.
-- ============================================================================

select id, slug, titulo from catalogo_produtos
where slug ilike 'mahindra-%' order by slug;

-- PASSO 2: aplica as specs por modelo.

