-- PASSO 3: conferência.
select slug, jsonb_array_length(especificacoes_detalhadas) as grupos
from catalogo_produtos where slug ilike 'mahindra-%'
and jsonb_array_length(especificacoes_detalhadas) > 0 order by slug;